defmodule MyAppWeb.MyController do
  use Phoenix.Controller

  def fetch_content(conn, params) do
    url = params["url"]
    |> String.trim()
    |> URI.parse()
    |> Map.get(:host)

    if allowed?(url) do
      HTTPoison.get!(url)
      |> handle_response(conn)
    else
      conn
      |> put_status(403)
      |> text("Forbidden")
    end
  end

  defp allowed?(url) do
    # Allowlist destinations
    allowlist = ["example.com", "example2.com"]

    # Block internal/private IP ranges
    if IP.parse(url).is_private? do
      false
    else
      # Tightly control redirects before making outbound requests
      case HTTPoison.head(url) do
        {:ok, %HTTPoison.Response{status_code: 301}} ->
          false
        _ ->
          true
      end
    end
  end

  defp handle_response(%HTTPoison.Response{} = response, conn) do
    body = response.body
    |> String.trim()
    |> String.replace("\n", "")

    conn
    |> put_resp_content_type("text/plain")
    |> send_resp(200, body)
  end
end